@import url('https://fonts.googleapis.com/css2?family=Nunito:wght@400;500;600;700;800;900&display=swap');

:root {
  --bg: #f5f5f7;
  --card: #ffffff;
  --sunken: #f0f0f5;
  --text1: #1d1d1f;
  --text2: #6e6e73;
  --text3: #aeaeb2;
  --green: #34c759;
  --green-dim: rgba(52,199,89,.12);
  --amber: #ff9f0a;
  --amber-dim: rgba(255,159,10,.12);
  --red: #ff3b30;
  --red-dim: rgba(255,59,48,.12);
  --sky: #0ea5e9;
  --sky-dim: rgba(14,165,233,.12);
  --indigo: #6366f1;
  --indigo-dim: rgba(99,102,241,.12);
  --gold: #f59e0b;
  --border: rgba(0,0,0,.07);
  --r-sm: 8px; --r-md: 14px; --r-lg: 20px; --r-pill: 9999px;
  --f: 'Nunito', system-ui, sans-serif;
  --smooth: cubic-bezier(.4,0,.2,1);
  --spring: cubic-bezier(.34,1.56,.64,1);
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }
body {
  font-family: var(--f);
  background: var(--bg);
  color: var(--text1);
  font-size: 13px;
  line-height: 1.4;
  -webkit-font-smoothing: antialiased;
}

#rt-root { display: flex; flex-direction: column; gap: 10px; padding: 10px; }

/* ── Toolbar ───────────────────────────────────────────────────────── */
#rt-toolbar {
  display: flex; align-items: center; gap: 8px;
  background: var(--card); border-radius: var(--r-md);
  padding: 10px 16px; border: 1px solid var(--border);
  flex-wrap: wrap;
}
.tb-quarter { font-weight: 900; font-size: 13px; }
.tb-dot { color: var(--text3); }
.tb-sub { font-size: 12px; color: var(--text2); font-weight: 500; }
.tb-spacer { flex: 1; }
.tb-btn {
  display: flex; align-items: center; gap: 5px;
  padding: 5px 12px; border-radius: var(--r-pill);
  border: 1.5px solid var(--border);
  background: transparent; cursor: pointer;
  font-family: var(--f); font-size: 11px; font-weight: 700;
  color: var(--text2); transition: all .2s var(--smooth);
}
.tb-btn:hover { background: var(--sunken); border-color: var(--text3); color: var(--text1); }
.tb-btn.active { background: var(--indigo-dim); border-color: var(--indigo); color: var(--indigo); }
.tb-badge {
  display: inline-flex; align-items: center;
  padding: 3px 8px; border-radius: var(--r-pill);
  font-size: 10.5px; font-weight: 700;
}
.tag-amber { color: var(--amber); background: var(--amber-dim); }
.tag-sky   { color: var(--sky);   background: var(--sky-dim); }

/* ── Table wrapper ─────────────────────────────────────────────────── */
#rt-wrap {
  background: var(--card);
  border-radius: var(--r-lg);
  border: 1px solid var(--border);
  overflow: hidden;
}
#rt-table {
  width: 100%; border-collapse: collapse;
  table-layout: fixed;
}

/* ── Table head ────────────────────────────────────────────────────── */
#rt-head tr {
  background: var(--sunken);
  border-bottom: 1.5px solid var(--border);
}
#rt-head th {
  padding: 9px 12px; text-align: left;
  font-size: 9.5px; font-weight: 700;
  text-transform: uppercase; letter-spacing: .5px;
  color: var(--text3); white-space: nowrap;
}
#rt-head th.col-score { width: 200px; }
#rt-head th.col-bk    { width: 22%; }
#rt-head th.col-pil   { width: 22%; }
#rt-head th.col-act   { width: 150px; }
#rt-head th.col-pipe  { width: 130px; }

/* ── Table body rows ───────────────────────────────────────────────── */
#rt-body tr {
  border-bottom: 1px solid var(--border);
  cursor: pointer;
  transition: background .15s var(--smooth);
  animation: fade-up .35s var(--smooth) both;
}
#rt-body tr:last-child { border-bottom: none; }
#rt-body tr:hover { background: rgba(0,0,0,.02); }
#rt-body tr.row-red  { border-left: 3px solid var(--red); }
#rt-body tr.row-amber { border-left: 3px solid var(--amber); }
#rt-body tr.row-green { border-left: 3px solid transparent; }

#rt-body td { padding: 10px 12px; vertical-align: middle; }

/* ── Rep name cell ─────────────────────────────────────────────────── */
.rep-cell { display: flex; align-items: center; gap: 8px; }
.rep-rank {
  width: 20px; height: 20px;
  display: flex; align-items: center; justify-content: center;
  border-radius: 50%; font-size: 10px; font-weight: 900;
  flex-shrink: 0;
}
.rank-1 { background: linear-gradient(135deg,#f59e0b,#fbbf24); color: white; }
.rank-2 { background: linear-gradient(135deg,#94a3b8,#cbd5e1); color: white; }
.rank-3 { background: linear-gradient(135deg,#d97706,#fbbf24); color: white; }
.rank-n { background: var(--sunken); color: var(--text3); font-size: 9px; }
.rep-name { font-weight: 800; font-size: 13px; }
.rep-lv {
  display: inline-flex; padding: 1px 5px; border-radius: var(--r-pill);
  font-size: 9px; font-weight: 800; background: var(--sunken); color: var(--text2);
}
.rep-fire { font-size: 11px; }

/* ── Score cell ────────────────────────────────────────────────────── */
.score-cell { display: flex; align-items: center; gap: 8px; }
.score-ring { display: block; flex-shrink: 0; }
.score-ring circle.rt { fill: none; stroke: var(--sunken); }
.score-ring circle.ra { fill: none; stroke-linecap: round; transform-origin: center; }
.fcast-stack { display: flex; flex-direction: column; gap: 3px; }
.fcast-badge {
  display: inline-flex; align-items: center;
  padding: 2px 6px; border-radius: var(--r-pill);
  font-size: 10px; font-weight: 800;
  width: fit-content;
}
.fc-commit { color: var(--indigo); background: var(--indigo-dim); }
.fc-hr     { color: var(--sky);    background: var(--sky-dim); }
.fc-delta-pos { color: var(--indigo); background: var(--indigo-dim); font-size: 9px; }
.fc-delta-neg { color: var(--red);    background: var(--red-dim);    font-size: 9px; }

/* ── Component bar cell ────────────────────────────────────────────── */
.cmp-cell { display: flex; flex-direction: column; gap: 5px; }
.cmp-top { display: flex; align-items: baseline; justify-content: space-between; gap: 4px; }
.cmp-att { font-size: 18px; font-weight: 900; }
.cmp-abs { font-size: 10.5px; color: var(--text2); font-weight: 600; }
.fbar-sm { width: 100%; }
.fbar-sm-track { position: relative; height: 7px; background: var(--sunken); border-radius: var(--r-pill); }
.fbar-sm-act {
  position: absolute; left: 0; top: 0; height: 100%;
  border-radius: var(--r-pill); max-width: 100%;
  transform: scaleX(0); transform-origin: left;
  animation: bar-grow .6s var(--smooth) .1s forwards;
}
.fbar-sm-hr {
  position: absolute; top: 0; height: 100%;
  background: repeating-linear-gradient(90deg, var(--sky) 0, var(--sky) 3px, transparent 3px, transparent 6px);
  border-radius: 0 var(--r-pill) var(--r-pill) 0;
  transform: scaleX(0); transform-origin: left;
  animation: bar-grow .6s var(--smooth) .2s forwards;
  max-width: 100%;
}
.fbar-sm-pin {
  position: absolute; top: -3px;
  width: 2px; height: calc(100% + 6px);
  background: var(--indigo); border-radius: 2px;
  transform: translateX(-50%);
}
.fbar-sm-pin::after {
  content: ''; position: absolute; bottom: -3px; left: 50%;
  transform: translateX(-50%);
  width: 6px; height: 6px;
  background: var(--indigo); border-radius: 50%;
  border: 1.5px solid white;
}
.fbar-sm-lbl { display: flex; align-items: center; gap: 4px; margin-top: 4px; flex-wrap: wrap; }
.fl-ist { font-size: 10px; font-weight: 800; }
.fl-hr  { font-size: 10px; font-weight: 700; color: var(--sky); }
.fl-cmt { font-size: 10px; font-weight: 700; color: var(--indigo); }

/* ── Activity cell ─────────────────────────────────────────────────── */
.act-cell { display: flex; gap: 10px; align-items: flex-start; }
.act-item { display: flex; flex-direction: column; align-items: center; gap: 1px; }
.act-val { font-size: 14px; font-weight: 900; }
.act-lbl { font-size: 8.5px; color: var(--text3); text-transform: uppercase; letter-spacing: .3px; }
.act-arr { font-size: 9px; font-weight: 700; }
.act-sep { font-size: 11px; color: var(--text3); align-self: center; }
.au { color: var(--green); }
.ad { color: var(--red); }
.ae { color: var(--text3); }

/* ── Pipeline cell ─────────────────────────────────────────────────── */
.pipe-cell { display: flex; flex-direction: column; gap: 5px; }
.pipe-kv { display: flex; align-items: baseline; gap: 4px; }
.pipe-val { font-size: 16px; font-weight: 900; }
.pipe-lbl { font-size: 9px; color: var(--text3); text-transform: uppercase; letter-spacing: .3px; }

/* ── Modal ─────────────────────────────────────────────────────────── */
#rt-backdrop {
  position: fixed; inset: 0;
  background: rgba(0,0,0,.4);
  backdrop-filter: blur(6px);
  -webkit-backdrop-filter: blur(6px);
  z-index: 1000;
  animation: fade-up .25s ease both;
}
#rt-modal-box {
  position: fixed; inset: 0;
  display: flex; align-items: center; justify-content: center;
  z-index: 1001; padding: 20px;
}
#rt-modal-inner {
  background: var(--card);
  border-radius: var(--r-lg);
  border: 1px solid var(--border);
  width: 100%; max-width: 680px;
  max-height: 85vh; overflow-y: auto;
  box-shadow: 0 24px 60px rgba(0,0,0,.18);
  animation: modal-in .3s var(--spring) both;
}
@keyframes modal-in {
  from { opacity: 0; transform: scale(.94) translateY(10px); }
  to   { opacity: 1; transform: scale(1) translateY(0); }
}
.modal-hd {
  display: flex; align-items: center; gap: 10px;
  padding: 18px 20px; border-bottom: 1px solid var(--border);
  position: sticky; top: 0; background: var(--card);
  border-radius: var(--r-lg) var(--r-lg) 0 0;
  z-index: 2;
}
.modal-name { font-size: 18px; font-weight: 900; }
.modal-close {
  margin-left: auto; padding: 6px 12px;
  border-radius: var(--r-pill); border: 1.5px solid var(--border);
  background: transparent; cursor: pointer;
  font-family: var(--f); font-size: 12px; font-weight: 700; color: var(--text2);
}
.modal-close:hover { background: var(--sunken); }
.modal-body { padding: 20px; display: flex; flex-direction: column; gap: 16px; }
.modal-section { display: flex; flex-direction: column; gap: 10px; }
.modal-section-title {
  font-size: 9.5px; font-weight: 700; text-transform: uppercase;
  letter-spacing: .6px; color: var(--text3);
}
.modal-grid-2 { display: grid; grid-template-columns: 1fr 1fr; gap: 10px; }
.modal-kv { display: flex; flex-direction: column; gap: 2px; }
.modal-kv-lbl { font-size: 9.5px; color: var(--text3); text-transform: uppercase; letter-spacing: .4px; font-weight: 700; }
.modal-kv-val { font-size: 22px; font-weight: 900; }
.modal-kv-sub { font-size: 11px; color: var(--text2); font-weight: 600; }
.fbar-lg { width: 100%; }
.fbar-lg-track { position: relative; height: 12px; background: var(--sunken); border-radius: var(--r-pill); }
.fbar-lg-act {
  position: absolute; left: 0; top: 0; height: 100%;
  border-radius: var(--r-pill); max-width: 100%;
  transform: scaleX(0); transform-origin: left;
  animation: bar-grow .7s var(--smooth) .1s forwards;
}
.fbar-lg-hr {
  position: absolute; top: 0; height: 100%;
  background: repeating-linear-gradient(90deg, var(--sky) 0, var(--sky) 5px, transparent 5px, transparent 10px);
  border-radius: 0 var(--r-pill) var(--r-pill) 0;
  transform: scaleX(0); transform-origin: left;
  animation: bar-grow .7s var(--smooth) .25s forwards;
  max-width: 100%;
}
.fbar-lg-pin {
  position: absolute; top: -5px;
  width: 3px; height: calc(100% + 10px);
  background: var(--indigo); border-radius: 2px;
  transform: translateX(-50%);
}
.fbar-lg-pin::after {
  content: ''; position: absolute; bottom: -5px; left: 50%;
  transform: translateX(-50%);
  width: 9px; height: 9px;
  background: var(--indigo); border-radius: 50%;
  border: 2px solid white;
  box-shadow: 0 0 0 1.5px var(--indigo);
}
.fbar-lg-lbls { display: flex; align-items: center; gap: 7px; margin-top: 7px; flex-wrap: wrap; }
.fbl-ist { font-size: 12px; font-weight: 800; }
.fbl-hr  { font-size: 12px; font-weight: 700; color: var(--sky); }
.fbl-cmt { font-size: 12px; font-weight: 700; color: var(--indigo); }
.fbl-d   { font-size: 10px; font-weight: 800; padding: 1px 6px; border-radius: var(--r-pill); }
.d-pos   { color: var(--indigo); background: var(--indigo-dim); }
.d-neg   { color: var(--red);    background: var(--red-dim); }
.coaching-item {
  padding: 8px 10px; border-radius: var(--r-sm);
  font-size: 11px; font-weight: 700;
}
.c-warn  { background: var(--amber-dim); color: var(--amber); }
.c-alert { background: var(--red-dim);   color: var(--red); }
.c-ok    { background: var(--green-dim); color: var(--green); }
.hidden { display: none !important; }

/* ── Animations ────────────────────────────────────────────────────── */
@keyframes ring-fill {
  from { stroke-dashoffset: var(--circ); }
  to   { stroke-dashoffset: var(--target); }
}
@keyframes bar-grow {
  from { transform: scaleX(0); }
  to   { transform: scaleX(1); }
}
@keyframes fade-up {
  from { opacity: 0; transform: translateY(6px); }
  to   { opacity: 1; transform: translateY(0); }
}
.c-green  { color: var(--green); }
.c-amber  { color: var(--amber); }
.c-red    { color: var(--red); }
.c-sky    { color: var(--sky); }
.c-indigo { color: var(--indigo); }

@media (max-width: 700px) {
  .col-act, .col-pipe { display: none; }
  #rt-head th.col-act, #rt-head th.col-pipe { display: none; }
}

