(function () {
'use strict';

var model = appsmith.model || {};
var reps  = model.reps || [];
var showDetails = false;

// ── Helpers ──────────────────────────────────────────────────────────────────
function clamp(v, lo, hi) {
  lo = lo == null ? 0 : lo;
  hi = hi == null ? 100 : hi;
  return Math.max(lo, Math.min(hi, v || 0));
}
function sc(v) {
  if (v >= 80) return 'var(--green)';
  if (v >= 60) return 'var(--amber)';
  return 'var(--red)';
}
function scCls(v) {
  if (v >= 80) return 'c-green';
  if (v >= 60) return 'c-amber';
  return 'c-red';
}
function eur(n) {
  if (n == null || isNaN(n)) return '\u2014';
  var abs = Math.abs(n), sign = n < 0 ? '-' : '';
  if (abs >= 1e6) return sign + '\u20ac' + (abs / 1e6).toFixed(1).replace(/\.0$/, '') + 'M';
  if (abs >= 1e3) return sign + '\u20ac' + Math.round(abs / 1e3) + 'k';
  return sign + '\u20ac' + Math.round(abs);
}
function pct(v) { return Math.round(v || 0) + '%'; }
function arr(t) {
  if (!t) return '';
  var cls = t.cls === 'green' ? 'au' : t.cls === 'red' ? 'ad' : 'ae';
  return '<span class="act-arr ' + cls + '">' + (t.arrow || '') + '</span>';
}
function shortName(full) {
  if (!full) return '—';
  var p = full.trim().split(' ');
  return p.length >= 2 ? p[0] + ' ' + p[p.length - 1][0] + '.' : full;
}

// ── Mini 3-ring (50px) ────────────────────────────────────────────────────────
function miniRing3(comp, bk, pil) {
  var rings = [
    { r: 18, v: clamp(comp), color: sc(comp), delay: '0ms' },
    { r: 13, v: clamp(bk),   color: sc(bk),   delay: '70ms' },
    { r: 8,  v: clamp(pil),  color: sc(pil),  delay: '140ms' },
  ];
  var arcs = rings.map(function (ring) {
    var sw = 4;
    var circ   = parseFloat((2 * Math.PI * ring.r).toFixed(1));
    var offset = parseFloat((circ * (1 - ring.v / 100)).toFixed(1));
    return '<circle class="rt" r="' + ring.r + '" cx="25" cy="25" stroke-width="' + sw + '"/>'
      + '<circle class="ra" r="' + ring.r + '" cx="25" cy="25" stroke-width="' + sw + '"'
      + ' stroke="' + ring.color + '"'
      + ' stroke-dasharray="' + circ + ' ' + circ + '"'
      + ' stroke-dashoffset="' + circ + '"'
      + ' style="transform:rotate(-90deg);transform-origin:25px 25px;"'
      + ' data-circ="' + circ + '" data-target="' + offset + '" data-delay="' + ring.delay + '"'
      + '/>';
  }).join('');
  return '<svg class="score-ring" width="50" height="50" viewBox="0 0 50 50">' + arcs + '</svg>';
}

// ── Small forecast bar ────────────────────────────────────────────────────────
function fbarSm(actual, hr, commit) {
  var a  = clamp(actual);
  var h  = Math.round(hr || 0);
  var hv = clamp(h, 0, 100);
  var av = clamp(a, 0, 100);
  var cv = commit > 0 ? clamp(commit, 0, 100) : 0;
  var hrStart = Math.min(av, hv);
  var hrWidth = Math.max(0, hv - av);
  var color   = sc(a);
  var cls     = scCls(a);
  var showHr  = h > 0 && h !== a;
  var showCmt = commit > 0;
  var showLbl = showHr || showCmt;
  return '<div class="fbar-sm">'
    + '<div class="fbar-sm-track">'
    +   '<div class="fbar-sm-act" style="width:' + av + '%;background:' + color + ';"></div>'
    +   (showHr && hrWidth > 0 ? '<div class="fbar-sm-hr" style="left:' + hrStart + '%;width:' + hrWidth + '%;"></div>' : '')
    +   (showCmt ? '<div class="fbar-sm-pin" style="left:' + cv + '%;"></div>' : '')
    + '</div>'
    + (showLbl ? '<div class="fbar-sm-lbl">'
    +   (showHr ? '<span class="fl-hr">Prognose ' + h + '%</span>' : '')
    +   (showCmt ? '<span class="fl-cmt">Commit ' + Math.round(commit) + '%</span>' : '')
    + '</div>' : '')
    + '</div>';
}

// ── Large forecast bar (for modal) ────────────────────────────────────────────
function fbarLg(actual, hr, commit) {
  var a  = clamp(actual);
  var h  = Math.round(hr || 0);
  var hv = clamp(h, 0, 100);
  var av = clamp(a, 0, 100);
  var cv = commit > 0 ? clamp(commit, 0, 100) : 0;
  var hrStart = Math.min(av, hv);
  var hrWidth = Math.max(0, hv - av);
  var color   = sc(a);
  var cls     = scCls(a);
  var showHr  = h > 0 && h !== a;
  var showCmt = commit > 0;
  var delta   = (showCmt && h > 0) ? Math.round(commit - h) : null;
  var dHtml   = '';
  if (delta !== null && delta !== 0) {
    var dCls = delta > 0 ? 'd-pos' : 'd-neg';
    dHtml = '<span class="fbl-d ' + dCls + '">' + (delta > 0 ? '+' : '') + delta + '%</span>';
  }
  return '<div class="fbar-lg">'
    + '<div class="fbar-lg-track">'
    +   '<div class="fbar-lg-act" style="width:' + av + '%;background:' + color + ';"></div>'
    +   (showHr && hrWidth > 0 ? '<div class="fbar-lg-hr" style="left:' + hrStart + '%;width:' + hrWidth + '%;"></div>' : '')
    +   (showCmt ? '<div class="fbar-lg-pin" style="left:' + cv + '%;"></div>' : '')
    + '</div>'
    + '<div class="fbar-lg-lbls">'
    +   '<span class="fbl-ist ' + cls + '">' + pct(a) + ' <small style="opacity:.6;font-weight:500">Att.</small></span>'
    +   (showHr ? '<span class="fbl-hr">Prognose ' + h + '%</span>' : '')
    +   (showCmt ? '<span class="fbl-cmt">Commit ' + Math.round(commit) + '%</span>' : '')
    +   dHtml
    + '</div>'
    + '</div>';
}

// ── Level detection ───────────────────────────────────────────────────────────
function getLevel(r) {
  var comp = r.composite || 0;
  if (comp >= 100) return 'L3';
  if (comp >= 80)  return 'L2';
  return 'L1';
}
function getFireEmoji(r) {
  var comp = r.composite || 0;
  if (comp >= 105) return '\ud83d\udd25\ud83d\udd25';
  if (comp >= 90)  return '\ud83d\udd25';
  return '';
}

// ── Render toolbar ────────────────────────────────────────────────────────────
function renderToolbar() {
  var ql   = model.quarterLabel || '\u2014';
  var hist = model.isHistorical;
  var cnt  = reps.length;
  var histBadge = hist
    ? '<span class="tb-badge tag-amber" style="margin-left:4px">\ud83d\udcc5 Historisch</span>'
    : '';
  var detailsActive = showDetails ? ' active' : '';
  document.getElementById('rt-toolbar').innerHTML =
    '<span class="tb-quarter">' + ql + '</span>'
    + '<span class="tb-dot">\u00b7</span>'
    + '<span class="tb-sub">' + cnt + ' Reps</span>'
    + histBadge
    + '<div class="tb-spacer"></div>'
    + '<button class="tb-btn' + detailsActive + '" id="btn-details">'
    + (showDetails ? '\u2212 Weniger' : '\u002b Details')
    + '</button>';

  document.getElementById('btn-details').addEventListener('click', function () {
    showDetails = !showDetails;
    render();
  });
}

// ── Render table head ─────────────────────────────────────────────────────────
function renderHead() {
  var detailCols = showDetails
    ? '<th class="col-act">Aktivit\u00e4t 30 Tage</th><th class="col-pipe">Pipeline</th>'
    : '';
  document.getElementById('rt-head').innerHTML =
    '<tr>'
    + '<th style="min-width:150px">Rep</th>'
    + '<th class="col-score">Score</th>'
    + '<th class="col-bk">Bookings</th>'
    + '<th class="col-pil">Piloten</th>'
    + detailCols
    + '</tr>';
}

// ── Render table body ─────────────────────────────────────────────────────────
function renderBody() {
  if (!reps.length) {
    document.getElementById('rt-body').innerHTML =
      '<tr><td colspan="6" style="text-align:center;padding:32px;color:var(--text3)">Keine Daten</td></tr>';
    return;
  }

  var rows = reps.map(function (r, idx) {
    var comp   = r.composite    || 0;
    var bkAtt  = r.bookingsAtt  || 0;
    var pilAtt = r.pilotenAtt   || 0;
    var bkHR   = r.forecastAtt  || 0;
    var bkCmt  = r.commitAtt    || 0;
    var pilHR  = r.pilotenForecastAtt || 0;
    var pilCmt = r.pilotCommitAtt     || 0;
    var cmtDev = r.commitDeviation    || 0;
    var status = r.overallStatus || 'green';

    // Rank badge
    var rankHtml = '';
    if (idx === 0)      rankHtml = '<span class="rep-rank rank-1">1</span>';
    else if (idx === 1) rankHtml = '<span class="rep-rank rank-2">2</span>';
    else if (idx === 2) rankHtml = '<span class="rep-rank rank-3">3</span>';
    else                rankHtml = '<span class="rep-rank rank-n">' + (idx+1) + '</span>';

    var fire  = getFireEmoji(r);
    var level = getLevel(r);
    var name  = shortName(r.repName || 'Unbekannt');

    // Forecast stack badges
    var cmtBadge = bkCmt > 0
      ? '<span class="fcast-badge fc-commit">Commit ' + pct(bkCmt) + '</span>' : '';
    var hrBadge  = bkHR > 0 && bkHR !== bkAtt
      ? '<span class="fcast-badge fc-hr">Prognose ' + pct(bkHR) + '</span>'  : '';
    var devBadge = '';
    if (cmtDev !== 0 && bkCmt > 0) {
      var dCls = cmtDev > 0 ? 'fc-delta-pos' : 'fc-delta-neg';
      var dSign = cmtDev > 0 ? '+' : '';
      devBadge = '<span class="fcast-badge ' + dCls + '">' + dSign + cmtDev + '%</span>';
    }

    // Activity cells (only if showDetails)
    var actHtml = '', pipeHtml = '';
    if (showDetails) {
      actHtml = '<td class="col-act">'
        + '<div class="act-cell">'
        +   '<div class="act-item"><span class="act-val">' + (r.l30TouchPerDay || 0).toFixed(1) + '</span>'
        +     '<span class="act-lbl">Touch</span>' + arr(r.l30TrendTouch) + '</div>'
        +   '<span class="act-sep">\u2192</span>'
        +   '<div class="act-item"><span class="act-val">' + (r.l30QualPerDay || 0).toFixed(1) + '</span>'
        +     '<span class="act-lbl">QT</span>' + arr(r.l30TrendQual) + '</div>'
        +   '<span class="act-sep">\u2192</span>'
        +   '<div class="act-item"><span class="act-val">' + (r.l30OppPerDay || 0).toFixed(1) + '</span>'
        +     '<span class="act-lbl">Opp</span>' + arr(r.l30TrendOpp) + '</div>'
        + '</div>'
        + '</td>';
      var covColor = (r.coverageVal || 0) >= 2.5 ? 'var(--green)' : (r.coverageVal || 0) >= 1.5 ? 'var(--amber)' : 'var(--red)';
      var stColor  = (r.staleRateVal || 0) <= 20 ? 'var(--green)' : (r.staleRateVal || 0) <= 40 ? 'var(--amber)' : 'var(--red)';
      pipeHtml = '<td class="col-pipe">'
        + '<div class="pipe-cell">'
        +   '<div class="pipe-kv"><span class="pipe-val" style="color:' + covColor + '">' + ((r.coverageVal || 0).toFixed(1)) + '\u00d7</span>'
        +     '<span class="pipe-lbl">Cov</span></div>'
        +   '<div class="pipe-kv"><span class="pipe-val" style="color:' + stColor + '">' + Math.round(100 - (r.staleRateVal || 0)) + '%</span>'
        +     '<span class="pipe-lbl">Ges.</span></div>'
        + '</div>'
        + '</td>';
    }

    var rowCls = 'row-' + status;
    return '<tr class="' + rowCls + '" data-idx="' + idx + '" style="animation-delay:' + (idx * 0.03) + 's">'
      + '<td>'
      +   '<div class="rep-cell">'
      +     rankHtml
      +     '<div>'
      +       '<div style="display:flex;align-items:center;gap:4px">'
      +         '<span class="rep-name">' + name + '</span>'
      +         (fire ? '<span class="rep-fire">' + fire + '</span>' : '')
      +       '</div>'
      +       '<span class="rep-lv">' + level + '</span>'
      +     '</div>'
      +   '</div>'
      + '</td>'
      + '<td>'
      +   '<div class="score-cell">'
      +     miniRing3(comp, bkAtt, pilAtt)
      +     '<div class="fcast-stack">'
      +       cmtBadge + hrBadge + devBadge
      +       ((!cmtBadge && !hrBadge) ? '<span class="fcast-badge" style="color:var(--text3);background:var(--sunken)">' + pct(comp) + '</span>' : '')
      +     '</div>'
      +   '</div>'
      + '</td>'
      + '<td>'
      +   '<div class="cmp-cell">'
      +     '<div class="cmp-top">'
      +       '<span class="cmp-att ' + scCls(bkAtt) + '">' + pct(bkAtt) + '</span>'
      +       '<span class="cmp-abs">' + eur(r.bookingsARR) + '</span>'
      +     '</div>'
      +     fbarSm(bkAtt, bkHR, bkCmt)
      +   '</div>'
      + '</td>'
      + '<td>'
      +   '<div class="cmp-cell">'
      +     '<div class="cmp-top">'
      +       '<span class="cmp-att ' + scCls(pilAtt) + '">' + pct(pilAtt) + '</span>'
      +       '<span class="cmp-abs">' + Math.round(r.pilotenCount || 0) + '</span>'
      +     '</div>'
      +     fbarSm(pilAtt, pilHR, pilCmt)
      +   '</div>'
      + '</td>'
      + actHtml
      + pipeHtml
      + '</tr>';
  }).join('');

  document.getElementById('rt-body').innerHTML = rows;

  // Click handlers
  document.querySelectorAll('#rt-body tr').forEach(function (tr) {
    tr.addEventListener('click', function () {
      var idx = parseInt(tr.getAttribute('data-idx'));
      openModal(reps[idx]);
    });
  });
}

// ── Modal ─────────────────────────────────────────────────────────────────────
function openModal(r) {
  var comp   = r.composite    || 0;
  var bkAtt  = r.bookingsAtt  || 0;
  var bkHR   = r.forecastAtt  || 0;
  var bkCmt  = r.commitAtt    || 0;
  var pilAtt = r.pilotenAtt   || 0;
  var pilHR  = r.pilotenForecastAtt || 0;
  var pilCmt = r.pilotCommitAtt     || 0;
  var name   = r.repName || '\u2014';
  var level  = getLevel(r);
  var fire   = getFireEmoji(r);

  // Coaching items
  var coaching = [];
  if ((r.staleRateVal || 0) > 30) {
    coaching.push({ cls: 'c-alert', text: '\u26a0\ufe0f Pipeline aufr\u00e4umen \u2014 ' + Math.round(r.staleRateVal) + '% Stale Opps' });
  }
  if ((r.overdueCount || 0) > 0) {
    coaching.push({ cls: 'c-alert', text: '\u26a0\ufe0f ' + r.overdueCount + ' \u00fcberf\u00e4llige Opportunities (' + eur(r.overdueArr) + ')' });
  }
  if ((r.coverageVal || 0) < 1.5) {
    coaching.push({ cls: 'c-warn', text: '\ud83d\udce6 Pipeline Coverage zu niedrig (' + (r.coverageVal || 0).toFixed(1) + '\u00d7)' });
  }
  if ((r.l30TouchPerDay || 0) < 30) {
    coaching.push({ cls: 'c-warn', text: '\ud83d\udcde Aktivit\u00e4t erh\u00f6hen \u2014 Touch/d: ' + (r.l30TouchPerDay || 0).toFixed(1) });
  }
  if (coaching.length === 0) {
    coaching.push({ cls: 'c-ok', text: '\u2713 Keine kritischen Punkte' });
  }
  var coachingHtml = coaching.map(function (c) {
    return '<div class="coaching-item ' + c.cls + '">' + c.text + '</div>';
  }).join('');

  document.getElementById('rt-modal-inner').innerHTML =
    '<div class="modal-hd">'
    +   '<div>'
    +     '<div style="display:flex;align-items:center;gap:6px">'
    +       '<span class="modal-name">' + name + '</span>'
    +       (fire ? '<span style="font-size:16px">' + fire + '</span>' : '')
    +     '</div>'
    +     '<span class="rep-lv">' + level + '</span>'
    +   '</div>'
    +   '<button class="modal-close" id="modal-close-btn">\u2715 Schlie\u00dfen</button>'
    + '</div>'
    + '<div class="modal-body">'

    +   '<div class="modal-section">'
    +     '<div class="modal-section-title">Attainment</div>'
    +     '<div>'
    +       '<div style="display:flex;align-items:baseline;gap:6px;margin-bottom:6px">'
    +         '<span style="font-size:11px;font-weight:700;color:var(--text3);text-transform:uppercase;letter-spacing:.5px">Bookings</span>'
    +         '<span style="font-size:11px;color:var(--text2)">' + eur(r.bookingsARR) + ' / ' + eur(r.bookingsTarget) + '</span>'
    +       '</div>'
    +       fbarLg(bkAtt, bkHR, bkCmt)
    +     '</div>'
    +     '<div style="margin-top:12px">'
    +       '<div style="display:flex;align-items:baseline;gap:6px;margin-bottom:6px">'
    +         '<span style="font-size:11px;font-weight:700;color:var(--text3);text-transform:uppercase;letter-spacing:.5px">Piloten</span>'
    +         '<span style="font-size:11px;color:var(--text2)">' + Math.round(r.pilotenCount || 0) + ' / ' + Math.round(r.pilotenTarget || 0) + '</span>'
    +       '</div>'
    +       fbarLg(pilAtt, pilHR, pilCmt)
    +     '</div>'
    +   '</div>'

    +   '<div class="modal-grid-2">'
    +     '<div class="modal-section">'
    +       '<div class="modal-section-title">Pipeline</div>'
    +       '<div class="modal-kv">'
    +         '<span class="modal-kv-lbl">Coverage</span>'
    +         '<span class="modal-kv-val" style="color:' + ((r.coverageVal||0) >= 2.5 ? 'var(--green)' : (r.coverageVal||0) >= 1.5 ? 'var(--amber)' : 'var(--red)') + '">' + ((r.coverageVal || 0).toFixed(1)) + '\u00d7</span>'
    +         '<span class="modal-kv-sub">' + eur(r.pipelineARR) + ' Pipeline</span>'
    +       '</div>'
    +       '<div class="modal-kv">'
    +         '<span class="modal-kv-lbl">Gesundheit</span>'
    +         '<span class="modal-kv-val" style="color:' + ((r.staleRateVal||0) <= 20 ? 'var(--green)' : (r.staleRateVal||0) <= 40 ? 'var(--amber)' : 'var(--red)') + '">' + Math.round(100 - (r.staleRateVal || 0)) + '%</span>'
    +         '<span class="modal-kv-sub">' + (r.staleCount || 0) + ' Stale Opps</span>'
    +       '</div>'
    +     '</div>'

    +     '<div class="modal-section">'
    +       '<div class="modal-section-title">Aktivit\u00e4t 30 Tage</div>'
    +       '<div style="display:flex;gap:10px;flex-wrap:wrap">'
    +         '<div class="modal-kv"><span class="modal-kv-lbl">Touch/d</span><span class="modal-kv-val">' + (r.l30TouchPerDay || 0).toFixed(1) + '</span></div>'
    +         '<div class="modal-kv"><span class="modal-kv-lbl">QT/d</span><span class="modal-kv-val">' + (r.l30QualPerDay || 0).toFixed(1) + '</span></div>'
    +         '<div class="modal-kv"><span class="modal-kv-lbl">Opp/d</span><span class="modal-kv-val">' + (r.l30OppPerDay || 0).toFixed(1) + '</span></div>'
    +       '</div>'
    +       '<div style="font-size:11px;color:var(--text2);font-weight:600;margin-top:4px">'
    +         'T\u2192QT ' + (r.l30TouchToQual || 0) + '% \u00b7 QT\u2192Opp ' + (r.l30QualToOpp || 0) + '%'
    +       '</div>'
    +     '</div>'
    +   '</div>'

    +   '<div class="modal-section">'
    +     '<div class="modal-section-title">\ud83d\udca1 Coaching</div>'
    +     coachingHtml
    +   '</div>'

    + '</div>';

  document.getElementById('rt-modal').style.display = 'block';

  document.getElementById('modal-close-btn').addEventListener('click', closeModal);
  document.getElementById('rt-backdrop').addEventListener('click', closeModal);
}

function closeModal() {
  document.getElementById('rt-modal').style.display = 'none';
}

// ── Main render ───────────────────────────────────────────────────────────────
function render() {
  try {
    model = appsmith.model || {};
    reps  = model.reps || [];
    renderToolbar();
    renderHead();
    renderBody();
    animateRings();
  } catch (e) {
    document.getElementById('rt-root').innerHTML =
      '<div style="padding:20px;color:var(--red);font-family:monospace;font-size:12px">'
      + '<strong>Render error:</strong><br>' + e.message + '</div>';
  }
}

function scCls(v) {
  if (v >= 80) return 'c-green';
  if (v >= 60) return 'c-amber';
  return 'c-red';
}

function animateRings() {
  document.querySelectorAll('[data-circ]').forEach(function(el) {
    var circ   = parseFloat(el.getAttribute('data-circ'));
    var target = parseFloat(el.getAttribute('data-target'));
    var delay  = parseInt(el.getAttribute('data-delay') || 0);
    el.style.strokeDashoffset = circ;
    setTimeout(function() {
      el.style.transition = 'stroke-dashoffset 0.85s cubic-bezier(0.4,0,0.2,1)';
      el.style.strokeDashoffset = target;
    }, delay + 50);
  });
}

appsmith.onReady(function () { render(); });
})();
